"use client";

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

// =============================================================================
// TYPES
// =============================================================================

interface AudioPlayerContextValue {
  isPlaying: boolean;
  currentTime: number;
  duration: number;
  volume: number;
  isMuted: boolean;
  playbackRate: number;
  isBuffering: boolean;
  hasEnded: boolean;
  error: string | null;
  play: () => void;
  pause: () => void;
  toggle: () => void;
  seek: (time: number) => void;
  setVolume: (volume: number) => void;
  toggleMute: () => void;
  setPlaybackRate: (rate: number) => void;
}

interface AudioPlayerProps extends React.ComponentProps<"div"> {
  /** Audio source URL */
  src: string;
  /** Initial volume (0-1) */
  initialVolume?: number;
  /** Whether to autoplay */
  autoplay?: boolean;
  /** Called when playback ends */
  onEnded?: () => void;
}

interface AudioPlayerControlsProps extends React.ComponentProps<"div"> {}

interface AudioPlayerProgressProps extends React.ComponentProps<"div"> {
  /** Height of the progress bar */
  height?: number;
}

interface AudioPlayerSpeedProps extends React.ComponentProps<"button"> {
  /** Available speed options */
  speeds?: number[];
}

// =============================================================================
// CONTEXT
// =============================================================================

const AudioPlayerContext = React.createContext<AudioPlayerContextValue | null>(
  null
);

function useAudioPlayerContext() {
  const context = React.useContext(AudioPlayerContext);
  if (!context) {
    throw new Error("AudioPlayer components must be used within AudioPlayer");
  }
  return context;
}

// =============================================================================
// VARIANTS
// =============================================================================

const audioPlayerVariants = cva(
  "flex flex-col gap-2 rounded-xl border border-border bg-background p-4",
  {
    variants: {
      size: {
        sm: "p-3 gap-1.5",
        md: "p-4 gap-2",
        lg: "p-5 gap-3",
      },
    },
    defaultVariants: {
      size: "md",
    },
  }
);

// =============================================================================
// HELPERS
// =============================================================================

function formatTime(seconds: number): string {
  if (!isFinite(seconds) || seconds < 0) return "0:00";
  const m = Math.floor(seconds / 60);
  const s = Math.floor(seconds % 60);
  return `${m}:${s.toString().padStart(2, "0")}`;
}

// =============================================================================
// COMPONENTS
// =============================================================================

function AudioPlayerRoot({
  src,
  initialVolume = 1,
  autoplay = false,
  onEnded,
  className,
  children,
  ...props
}: AudioPlayerProps & VariantProps<typeof audioPlayerVariants>) {
  const audioRef = React.useRef<HTMLAudioElement | null>(null);
  const [isPlaying, setIsPlaying] = React.useState(false);
  const [currentTime, setCurrentTime] = React.useState(0);
  const [duration, setDuration] = React.useState(0);
  const [volume, setVolumeState] = React.useState(initialVolume);
  const [isMuted, setIsMuted] = React.useState(false);
  const [playbackRate, setPlaybackRateState] = React.useState(1);
  const [isBuffering, setIsBuffering] = React.useState(false);
  const [hasEnded, setHasEnded] = React.useState(false);
  const [error, setError] = React.useState<string | null>(null);

  React.useEffect(() => {
    const audio = new Audio();
    audio.preload = "metadata";
    audio.volume = initialVolume;
    audioRef.current = audio;

    const handleTimeUpdate = () => setCurrentTime(audio.currentTime);
    const handleDuration = () => {
      if (isFinite(audio.duration)) setDuration(audio.duration);
    };
    const handlePlay = () => {
      setIsPlaying(true);
      setHasEnded(false);
    };
    const handlePause = () => setIsPlaying(false);
    const handleEnded = () => {
      setIsPlaying(false);
      setHasEnded(true);
      onEnded?.();
    };
    const handleWaiting = () => setIsBuffering(true);
    const handleCanPlay = () => setIsBuffering(false);
    const handleError = () =>
      setError(audio.error?.message || "Failed to load audio");

    audio.addEventListener("timeupdate", handleTimeUpdate);
    audio.addEventListener("durationchange", handleDuration);
    audio.addEventListener("loadedmetadata", handleDuration);
    audio.addEventListener("play", handlePlay);
    audio.addEventListener("pause", handlePause);
    audio.addEventListener("ended", handleEnded);
    audio.addEventListener("waiting", handleWaiting);
    audio.addEventListener("canplay", handleCanPlay);
    audio.addEventListener("error", handleError);

    return () => {
      audio.removeEventListener("timeupdate", handleTimeUpdate);
      audio.removeEventListener("durationchange", handleDuration);
      audio.removeEventListener("loadedmetadata", handleDuration);
      audio.removeEventListener("play", handlePlay);
      audio.removeEventListener("pause", handlePause);
      audio.removeEventListener("ended", handleEnded);
      audio.removeEventListener("waiting", handleWaiting);
      audio.removeEventListener("canplay", handleCanPlay);
      audio.removeEventListener("error", handleError);
      audio.pause();
      audio.removeAttribute("src");
      audio.load();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  React.useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    setError(null);
    setHasEnded(false);
    setCurrentTime(0);
    setDuration(0);
    audio.src = src;
    audio.load();
    if (autoplay) {
      audio.play().catch(() => {});
    }
  }, [src, autoplay]);

  const play = React.useCallback(() => {
    audioRef.current?.play().catch(() => {});
  }, []);

  const pause = React.useCallback(() => {
    audioRef.current?.pause();
  }, []);

  const toggle = React.useCallback(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (audio.paused) audio.play().catch(() => {});
    else audio.pause();
  }, []);

  const seek = React.useCallback((time: number) => {
    const audio = audioRef.current;
    if (!audio) return;
    audio.currentTime = Math.max(0, Math.min(time, audio.duration || 0));
  }, []);

  const setVolume = React.useCallback((vol: number) => {
    const audio = audioRef.current;
    if (!audio) return;
    const clamped = Math.max(0, Math.min(1, vol));
    audio.volume = clamped;
    setVolumeState(clamped);
  }, []);

  const toggleMute = React.useCallback(() => {
    const audio = audioRef.current;
    if (!audio) return;
    audio.muted = !audio.muted;
    setIsMuted(audio.muted);
  }, []);

  const setPlaybackRate = React.useCallback((rate: number) => {
    const audio = audioRef.current;
    if (!audio) return;
    audio.playbackRate = rate;
    setPlaybackRateState(rate);
  }, []);

  const contextValue = React.useMemo(
    () => ({
      isPlaying,
      currentTime,
      duration,
      volume,
      isMuted,
      playbackRate,
      isBuffering,
      hasEnded,
      error,
      play,
      pause,
      toggle,
      seek,
      setVolume,
      toggleMute,
      setPlaybackRate,
    }),
    [
      isPlaying,
      currentTime,
      duration,
      volume,
      isMuted,
      playbackRate,
      isBuffering,
      hasEnded,
      error,
      play,
      pause,
      toggle,
      seek,
      setVolume,
      toggleMute,
      setPlaybackRate,
    ]
  );

  return (
    <AudioPlayerContext.Provider value={contextValue}>
      <div
        data-slot="audio-player"
        className={cn(
          audioPlayerVariants({
            size: props.size as "sm" | "md" | "lg" | undefined,
          }),
          className
        )}
        {...props}
      >
        {children || (
          <>
            <AudioPlayerProgress />
            <AudioPlayerControls />
          </>
        )}
      </div>
    </AudioPlayerContext.Provider>
  );
}

function AudioPlayerProgress({
  height = 4,
  className,
  ...props
}: AudioPlayerProgressProps) {
  const { currentTime, duration, seek } = useAudioPlayerContext();
  const progressRef = React.useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = React.useState(false);

  const percentage = duration > 0 ? (currentTime / duration) * 100 : 0;

  const handleSeek = React.useCallback(
    (clientX: number) => {
      const el = progressRef.current;
      if (!el || !duration) return;
      const rect = el.getBoundingClientRect();
      const ratio = Math.max(
        0,
        Math.min(1, (clientX - rect.left) / rect.width)
      );
      seek(ratio * duration);
    },
    [duration, seek]
  );

  const handlePointerDown = React.useCallback(
    (e: React.PointerEvent) => {
      setIsDragging(true);
      handleSeek(e.clientX);
      (e.target as HTMLElement).setPointerCapture(e.pointerId);
    },
    [handleSeek]
  );

  const handlePointerMove = React.useCallback(
    (e: React.PointerEvent) => {
      if (isDragging) handleSeek(e.clientX);
    },
    [isDragging, handleSeek]
  );

  const handlePointerUp = React.useCallback(() => {
    setIsDragging(false);
  }, []);

  return (
    <div
      data-slot="audio-player-progress"
      className={cn("space-y-1", className)}
      {...props}
    >
      <div
        ref={progressRef}
        role="slider"
        aria-valuenow={Math.round(currentTime)}
        aria-valuemin={0}
        aria-valuemax={Math.round(duration)}
        aria-label="Audio progress"
        tabIndex={0}
        className="relative cursor-pointer rounded-full bg-muted group"
        style={{ height }}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
      >
        <div
          className="absolute inset-y-0 left-0 rounded-full bg-primary transition-[width] duration-75"
          style={{ width: `${percentage}%` }}
        />
        <div
          className="absolute top-1/2 -translate-y-1/2 w-3 h-3 rounded-full bg-primary opacity-0 group-hover:opacity-100 transition-opacity"
          style={{ left: `${percentage}%`, marginLeft: -6 }}
        />
      </div>
      <div className="flex justify-between text-xs text-muted-foreground font-mono tabular-nums">
        <span>{formatTime(currentTime)}</span>
        <span>{formatTime(duration)}</span>
      </div>
    </div>
  );
}

function AudioPlayerControls({
  className,
  children,
  ...props
}: AudioPlayerControlsProps) {
  const { isPlaying, toggle, isBuffering, error } = useAudioPlayerContext();

  if (error) {
    return (
      <div
        className={cn(
          "flex items-center justify-center py-2 text-sm text-destructive",
          className
        )}
        {...props}
      >
        Failed to load audio
      </div>
    );
  }

  return (
    <div
      data-slot="audio-player-controls"
      className={cn("flex items-center justify-center gap-3", className)}
      {...props}
    >
      {children || (
        <button
          type="button"
          onClick={toggle}
          disabled={isBuffering}
          className={cn(
            "flex items-center justify-center w-10 h-10 rounded-full",
            "bg-primary text-primary-foreground",
            "hover:bg-primary/90 transition-colors",
            "disabled:opacity-50 disabled:pointer-events-none"
          )}
          aria-label={isPlaying ? "Pause" : "Play"}
        >
          {isBuffering ? (
            <svg width="16" height="16" viewBox="0 0 16 16" fill="currentColor">
              <circle cx="4" cy="8" r="1.5" opacity="0.6">
                <animate
                  attributeName="opacity"
                  values="0.6;1;0.6"
                  dur="1s"
                  repeatCount="indefinite"
                />
              </circle>
              <circle cx="8" cy="8" r="1.5" opacity="0.6">
                <animate
                  attributeName="opacity"
                  values="0.6;1;0.6"
                  dur="1s"
                  begin="0.2s"
                  repeatCount="indefinite"
                />
              </circle>
              <circle cx="12" cy="8" r="1.5" opacity="0.6">
                <animate
                  attributeName="opacity"
                  values="0.6;1;0.6"
                  dur="1s"
                  begin="0.4s"
                  repeatCount="indefinite"
                />
              </circle>
            </svg>
          ) : isPlaying ? (
            <svg width="16" height="16" viewBox="0 0 16 16" fill="currentColor">
              <rect x="3" y="2" width="4" height="12" rx="1" />
              <rect x="9" y="2" width="4" height="12" rx="1" />
            </svg>
          ) : (
            <svg width="16" height="16" viewBox="0 0 16 16" fill="currentColor">
              <path d="M4 2.5v11l10-5.5z" />
            </svg>
          )}
        </button>
      )}
    </div>
  );
}

function AudioPlayerSpeed({
  speeds = [0.5, 0.75, 1, 1.25, 1.5, 2],
  className,
  ...props
}: AudioPlayerSpeedProps) {
  const { playbackRate, setPlaybackRate } = useAudioPlayerContext();

  const cycleSpeed = React.useCallback(() => {
    const currentIndex = speeds.indexOf(playbackRate);
    const nextIndex = (currentIndex + 1) % speeds.length;
    setPlaybackRate(speeds[nextIndex]);
  }, [speeds, playbackRate, setPlaybackRate]);

  return (
    <button
      type="button"
      data-slot="audio-player-speed"
      onClick={cycleSpeed}
      className={cn(
        "px-2 py-1 rounded-md text-xs font-mono tabular-nums",
        "bg-muted text-muted-foreground hover:bg-muted/80",
        "transition-colors",
        className
      )}
      aria-label={`Playback speed: ${playbackRate}x`}
      {...props}
    >
      {playbackRate}x
    </button>
  );
}

// =============================================================================
// COMPOUND COMPONENT
// =============================================================================

AudioPlayerRoot.displayName = "AudioPlayer";
AudioPlayerProgress.displayName = "AudioPlayer.Progress";
AudioPlayerControls.displayName = "AudioPlayer.Controls";
AudioPlayerSpeed.displayName = "AudioPlayer.Speed";

const AudioPlayer = Object.assign(AudioPlayerRoot, {
  Progress: AudioPlayerProgress,
  Controls: AudioPlayerControls,
  Speed: AudioPlayerSpeed,
});

export { AudioPlayer, useAudioPlayerContext, audioPlayerVariants, formatTime };
export type {
  AudioPlayerProps,
  AudioPlayerControlsProps,
  AudioPlayerProgressProps,
  AudioPlayerSpeedProps,
};

"use client";

import { useCallback, useEffect, useRef, useState, useMemo } from "react";

// =============================================================================
// TYPES
// =============================================================================

interface AudioPlayerState {
  /** Whether audio is currently playing */
  isPlaying: boolean;
  /** Current playback position in seconds */
  currentTime: number;
  /** Total duration of the audio in seconds */
  duration: number;
  /** Current volume (0-1) */
  volume: number;
  /** Whether audio is muted */
  isMuted: boolean;
  /** Current playback speed */
  playbackRate: number;
  /** Whether audio is buffering */
  isBuffering: boolean;
  /** Whether audio has ended */
  hasEnded: boolean;
  /** Error message if any */
  error: string | null;
}

interface AudioPlayerActions {
  /** Play the audio */
  play: () => void;
  /** Pause the audio */
  pause: () => void;
  /** Toggle play/pause */
  toggle: () => void;
  /** Seek to a specific time in seconds */
  seek: (time: number) => void;
  /** Set the volume (0-1) */
  setVolume: (volume: number) => void;
  /** Toggle mute */
  toggleMute: () => void;
  /** Set playback speed */
  setPlaybackRate: (rate: number) => void;
  /** Load a new audio source */
  load: (src: string) => void;
}

interface UseAudioPlayerOptions {
  /** Audio source URL */
  src?: string;
  /** Initial volume (0-1) */
  initialVolume?: number;
  /** Initial playback rate */
  initialPlaybackRate?: number;
  /** Whether to autoplay */
  autoplay?: boolean;
  /** Called when playback ends */
  onEnded?: () => void;
  /** Called when time updates */
  onTimeUpdate?: (time: number) => void;
  /** Called on error */
  onError?: (error: string) => void;
}

type UseAudioPlayerReturn = AudioPlayerState &
  AudioPlayerActions & {
    /** Reference to the underlying HTMLAudioElement */
    audioRef: React.RefObject<HTMLAudioElement | null>;
  };

// =============================================================================
// HOOK
// =============================================================================

export function useAudioPlayer(
  options: UseAudioPlayerOptions = {}
): UseAudioPlayerReturn {
  const {
    src,
    initialVolume = 1,
    initialPlaybackRate = 1,
    autoplay = false,
    onEnded,
    onTimeUpdate,
    onError,
  } = options;

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolumeState] = useState(initialVolume);
  const [isMuted, setIsMuted] = useState(false);
  const [playbackRate, setPlaybackRateState] = useState(initialPlaybackRate);
  const [isBuffering, setIsBuffering] = useState(false);
  const [hasEnded, setHasEnded] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Create audio element on mount
  useEffect(() => {
    const audio = new Audio();
    audio.preload = "metadata";
    audio.volume = initialVolume;
    audio.playbackRate = initialPlaybackRate;
    audioRef.current = audio;

    return () => {
      audio.pause();
      audio.removeAttribute("src");
      audio.load();
      audioRef.current = null;
    };
    // Only run on mount/unmount
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Set up event listeners
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const handleTimeUpdate = () => {
      const time = audio.currentTime;
      setCurrentTime(time);
      onTimeUpdate?.(time);
    };

    const handleDurationChange = () => {
      if (audio.duration && isFinite(audio.duration)) {
        setDuration(audio.duration);
      }
    };

    const handlePlay = () => {
      setIsPlaying(true);
      setHasEnded(false);
    };

    const handlePause = () => {
      setIsPlaying(false);
    };

    const handleEnded = () => {
      setIsPlaying(false);
      setHasEnded(true);
      onEnded?.();
    };

    const handleWaiting = () => setIsBuffering(true);
    const handleCanPlay = () => setIsBuffering(false);

    const handleError = () => {
      const msg = audio.error?.message || "Failed to load audio";
      setError(msg);
      setIsPlaying(false);
      onError?.(msg);
    };

    audio.addEventListener("timeupdate", handleTimeUpdate);
    audio.addEventListener("durationchange", handleDurationChange);
    audio.addEventListener("loadedmetadata", handleDurationChange);
    audio.addEventListener("play", handlePlay);
    audio.addEventListener("pause", handlePause);
    audio.addEventListener("ended", handleEnded);
    audio.addEventListener("waiting", handleWaiting);
    audio.addEventListener("canplay", handleCanPlay);
    audio.addEventListener("error", handleError);

    return () => {
      audio.removeEventListener("timeupdate", handleTimeUpdate);
      audio.removeEventListener("durationchange", handleDurationChange);
      audio.removeEventListener("loadedmetadata", handleDurationChange);
      audio.removeEventListener("play", handlePlay);
      audio.removeEventListener("pause", handlePause);
      audio.removeEventListener("ended", handleEnded);
      audio.removeEventListener("waiting", handleWaiting);
      audio.removeEventListener("canplay", handleCanPlay);
      audio.removeEventListener("error", handleError);
    };
  }, [onEnded, onTimeUpdate, onError]);

  // Load source
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio || !src) return;

    setError(null);
    setHasEnded(false);
    setCurrentTime(0);
    setDuration(0);
    audio.src = src;
    audio.load();

    if (autoplay) {
      audio.play().catch(() => {
        // Autoplay may be blocked by browser policy
      });
    }
  }, [src, autoplay]);

  const play = useCallback(() => {
    const audio = audioRef.current;
    if (!audio) return;
    audio.play().catch(() => {
      // Playback may be blocked by browser policy
    });
  }, []);

  const pause = useCallback(() => {
    audioRef.current?.pause();
  }, []);

  const toggle = useCallback(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (audio.paused) {
      audio.play().catch(() => {});
    } else {
      audio.pause();
    }
  }, []);

  const seek = useCallback((time: number) => {
    const audio = audioRef.current;
    if (!audio) return;
    const clamped = Math.max(0, Math.min(time, audio.duration || 0));
    audio.currentTime = clamped;
    setCurrentTime(clamped);
  }, []);

  const setVolume = useCallback((vol: number) => {
    const audio = audioRef.current;
    if (!audio) return;
    const clamped = Math.max(0, Math.min(1, vol));
    audio.volume = clamped;
    setVolumeState(clamped);
  }, []);

  const toggleMute = useCallback(() => {
    const audio = audioRef.current;
    if (!audio) return;
    audio.muted = !audio.muted;
    setIsMuted(audio.muted);
  }, []);

  const setPlaybackRate = useCallback((rate: number) => {
    const audio = audioRef.current;
    if (!audio) return;
    audio.playbackRate = rate;
    setPlaybackRateState(rate);
  }, []);

  const load = useCallback((newSrc: string) => {
    const audio = audioRef.current;
    if (!audio) return;
    setError(null);
    setHasEnded(false);
    setCurrentTime(0);
    setDuration(0);
    audio.src = newSrc;
    audio.load();
  }, []);

  return useMemo(
    () => ({
      // State
      isPlaying,
      currentTime,
      duration,
      volume,
      isMuted,
      playbackRate,
      isBuffering,
      hasEnded,
      error,
      // Actions
      play,
      pause,
      toggle,
      seek,
      setVolume,
      toggleMute,
      setPlaybackRate,
      load,
      // Ref
      audioRef,
    }),
    [
      isPlaying,
      currentTime,
      duration,
      volume,
      isMuted,
      playbackRate,
      isBuffering,
      hasEnded,
      error,
      play,
      pause,
      toggle,
      seek,
      setVolume,
      toggleMute,
      setPlaybackRate,
      load,
    ]
  );
}

export type {
  UseAudioPlayerOptions,
  UseAudioPlayerReturn,
  AudioPlayerState,
  AudioPlayerActions,
};
